import{_ as a,o as e,c as o,a3 as i}from"./chunks/framework.BTFg6ESq.js";const p=JSON.parse('{"title":"文件路径转附件 (Path to Attachment)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/messages/path-to-attachment.md","filePath":"user-guide/tools/llm-chat/messages/path-to-attachment.md","lastUpdated":1778239080000}'),n={name:"user-guide/tools/llm-chat/messages/path-to-attachment.md"};function r(l,t,s,c,d,h){return e(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="文件路径转附件-path-to-attachment" tabindex="-1">文件路径转附件 (Path to Attachment) <a class="header-anchor" href="#文件路径转附件-path-to-attachment" aria-label="Permalink to &quot;文件路径转附件 (Path to Attachment)&quot;">​</a></h1><p>在处理从外部软件（如 QQ、微信、飞书）粘贴的消息记录，或直接引用本地文件时，内容往往包含本地绝对路径。系统提供了一套智能的“路径转附件”机制，能够自动识别这些路径并将其转换为系统可管理的附件。</p><h2 id="一、-核心功能" tabindex="-1">一、 核心功能 <a class="header-anchor" href="#一、-核心功能" aria-label="Permalink to &quot;一、 核心功能&quot;">​</a></h2><h3 id="_1-1-一键转换-input-conversion" tabindex="-1">1.1 一键转换 (Input Conversion) <a class="header-anchor" href="#_1-1-一键转换-input-conversion" aria-label="Permalink to &quot;1.1 一键转换 (Input Conversion)&quot;">​</a></h3><p>当输入框中包含本地文件路径时，可以通过输入工具栏中的“更多工具”菜单触发转换。</p><ul><li><strong>操作路径</strong>: 输入框工具栏 -&gt; <code>...</code> (更多) -&gt; <strong>路径转附件</strong>。</li><li><strong>识别范围</strong>: <ul><li>标准 <code>file://</code> 协议链接。</li><li>Windows 绝对路径 (如 <code>C:\\Users\\Pictures\\image.png</code>)。</li><li>Unix/macOS 绝对路径 (如 <code>/Users/Documents/file.pdf</code>)。</li></ul></li><li><strong>处理流程</strong>: <ol><li><strong>智能识别</strong>: 系统使用正则表达式扫描输入框全文，提取所有合法的本地路径。</li><li><strong>资产化</strong>: 调用资产管理器将识别出的文件导入到应用的资产库中（Assetization）。</li><li><strong>占位符替换</strong>: 将输入框中的原始路径字符串替换为结构化的附件占位符。</li></ol></li></ul><h3 id="_1-2-自动占位符机制" tabindex="-1">1.2 自动占位符机制 <a class="header-anchor" href="#_1-2-自动占位符机制" aria-label="Permalink to &quot;1.2 自动占位符机制&quot;">​</a></h3><p>为了实现文本与媒体资源的解耦，系统使用占位符来表示附件在文本中的位置：</p><ul><li><strong>正式占位符</strong>: <code>【file::assetId】</code> —— 当文件已成功导入资产库后使用。</li><li><strong>上传中占位符</strong>: <code>【file::uploading:tempId】</code> —— 当文件正在导入或上传过程中使用。</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">**自愈机制 (Self-healing)**</p><p>系统内置了占位符自愈逻辑。当一个大文件上传完成，其临时 ID 变为真实资产 ID 时，输入框中的 <code>uploading</code> 占位符会自动更新为正式占位符，无需用户手动干预。</p></div><h2 id="二、-渲染映射-rendering-mapping" tabindex="-1">二、 渲染映射 (Rendering Mapping) <a class="header-anchor" href="#二、-渲染映射-rendering-mapping" aria-label="Permalink to &quot;二、 渲染映射 (Rendering Mapping)&quot;">​</a></h2><p>转换后的占位符在消息发送后，会根据文件类型在聊天界面中进行差异化渲染：</p><ul><li><strong>图片/表情包</strong>: 直接在消息流中渲染图片预览，支持点击放大。</li><li><strong>音频/视频</strong>: 渲染为带控制条的播放器。</li><li><strong>普通文件</strong>: 渲染为包含文件名、大小和图标的文件卡片。</li></ul><h3 id="安全资源转换" tabindex="-1">安全资源转换 <a class="header-anchor" href="#安全资源转换" aria-label="Permalink to &quot;安全资源转换&quot;">​</a></h3><p>由于浏览器安全沙箱限制，直接引用 <code>file://</code> 路径通常无法显示。本系统在渲染阶段会自动将占位符映射到 Tauri 的安全资源 URL (<code>convertFileSrc</code>)，确保本地资源在不破坏安全性的前提下正常展示。</p><h2 id="三、-进阶用法" tabindex="-1">三、 进阶用法 <a class="header-anchor" href="#三、-进阶用法" aria-label="Permalink to &quot;三、 进阶用法&quot;">​</a></h2><h3 id="_3-1-与快捷操作联动" tabindex="-1">3.1 与快捷操作联动 <a class="header-anchor" href="#_3-1-与快捷操作联动" aria-label="Permalink to &quot;3.1 与快捷操作联动&quot;">​</a></h3><p>你可以在<a href="./../quick-actions/">快捷操作</a>模板中预设包含本地路径的内容。 例如，创建一个“发送常用图片”的快捷操作，内容设置为 <code>C:\\Assets\\logo.png</code>。点击该快捷操作后，再配合“路径转附件”功能，即可快速发送本地资源。</p><h3 id="_3-2-清理无效占位符" tabindex="-1">3.2 清理无效占位符 <a class="header-anchor" href="#_3-2-清理无效占位符" aria-label="Permalink to &quot;3.2 清理无效占位符&quot;">​</a></h3><p>如果你在输入框中删除了某个附件卡片，但文本中残留了对应的 <code>【file::...】</code> 占位符，可以使用清理工具：</p><ul><li><strong>操作</strong>: 工具栏 -&gt; <code>...</code> (更多) -&gt; <strong>清理无效占位符</strong>。</li><li><strong>效果</strong>: 系统会自动扫描并移除所有在当前附件列表中找不到对应实体的占位符。</li></ul><h2 id="四、-常见问题" tabindex="-1">四、 常见问题 <a class="header-anchor" href="#四、-常见问题" aria-label="Permalink to &quot;四、 常见问题&quot;">​</a></h2><p><strong>Q: 为什么点击转换后提示“转换失败”？</strong> A: 请检查路径是否正确，以及应用是否有权限访问该文件。如果文件已被移动或删除，转换将无法进行。</p><p><strong>Q: 粘贴带图消息时会自动转换吗？</strong> A: 如果你从外部软件复制了带图片的富文本，系统在粘贴时会尝试提取其中的图片并直接作为附件添加。对于纯文本中的路径，建议手动触发一次“路径转附件”以确保渲染效果。</p>',24)])])}const u=a(n,[["render",r]]);export{p as __pageData,u as default};
